package archtest

// assembly_invariants_test.go — consolidated AST guards for assembly-related invariants.
//
// Invariants covered:
//   ASSEMBLY-MODULES-GEN-01            cmd/*/modules_gen.go must carry DO NOT EDIT marker,
//                                      declare package main, expose generatedCellModules() []CellModule
//   ASSEMBLY-MODULES-SWITCH-FORBIDDEN-02   cmd/ source must not contain switch on known cell-ID literals
//   ASSEMBLY-MAXCONSISTENCY-DERIVED-03  AssemblyMeta.MaxConsistencyLevel must carry yaml:"-"
//   ASSEMBLY-CELLMODULE-TYPE-04         cmd/{id}/ must declare top-level CellModule type
//   ASSEMBLY-SNAPSHOTS-LOCKED-01        writes to *.snapshots in kernel/assembly/ must be inside mu.Lock()
//   ASSEMBLYREF-METHOD-SET-01           cell.AssemblyRef interface must have exactly 3 methods

import (
	"bufio"
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"gopkg.in/yaml.v3"
)

// ---- ASSEMBLY-MODULES-GEN-01 / ASSEMBLY-MODULES-SWITCH-FORBIDDEN-02 /
//      ASSEMBLY-MAXCONSISTENCY-DERIVED-03 / ASSEMBLY-CELLMODULE-TYPE-04 ----

const (
	ruleAssemblyModulesGen01            = "ASSEMBLY-MODULES-GEN-01"
	ruleAssemblySwitchForbidden02       = "ASSEMBLY-MODULES-SWITCH-FORBIDDEN-02"
	ruleAssemblyMaxConsistencyDerived03 = "ASSEMBLY-MAXCONSISTENCY-DERIVED-03"
	ruleAssemblyCellModuleType04        = "ASSEMBLY-CELLMODULE-TYPE-04"
)

// generatedMarkerPrefix is the exact prefix every modules_gen.go must start with.
const generatedMarkerPrefix = "// Code generated by gocell generate assembly. DO NOT EDIT."

// loadKnownCellIDs derives the set of platform cell IDs from cells/*/cell.yaml.
// Source-of-truth is the filesystem layout + YAML id field; we deliberately
// avoid kernel/metadata so the archtest stays self-contained (yaml.v3 only).
// Fail-closed: zero matches, missing id, or directory/id mismatch all fail.
//
// ref: kubernetes/kubernetes hack/update-codegen.sh — annotation/glob discovery
// ref: bazelbuild/bazel-gazelle cmd/gazelle — walk filesystem, no static list
// ref: eslint/eslint Makefile.js checkRuleFiles — bidirectional cross-check
func loadKnownCellIDs(t *testing.T) []string {
	t.Helper()
	root := findModuleRoot(t)
	matches, err := filepath.Glob(filepath.Join(root, "cells", "*", "cell.yaml"))
	require.NoError(t, err, "%s: glob cells/*/cell.yaml", ruleAssemblySwitchForbidden02)
	require.NotEmpty(t, matches,
		"%s: no cells/*/cell.yaml found — derived set would be empty (fail-closed)",
		ruleAssemblySwitchForbidden02)

	ids := make([]string, 0, len(matches))
	for _, path := range matches {
		data, err := os.ReadFile(filepath.Clean(path))
		require.NoError(t, err, "%s: read %s", ruleAssemblySwitchForbidden02, path)
		var doc struct {
			ID string `yaml:"id"`
		}
		require.NoError(t, yaml.Unmarshal(data, &doc),
			"%s: parse %s", ruleAssemblySwitchForbidden02, path)
		require.NotEmpty(t, doc.ID,
			"%s: %s has empty id field", ruleAssemblySwitchForbidden02, path)
		dirName := filepath.Base(filepath.Dir(path))
		require.Equal(t, dirName, doc.ID,
			"%s: cell directory %q does not match yaml id %q",
			ruleAssemblySwitchForbidden02, dirName, doc.ID)
		ids = append(ids, doc.ID)
	}
	sort.Strings(ids)
	return ids
}

// INVARIANT: ASSEMBLY-MODULES-GEN-01
//
// TestAssemblyModulesGen_HasGeneratedMarker enforces ASSEMBLY-MODULES-GEN-01:
// every cmd/*/modules_gen.go file must carry the canonical DO NOT EDIT marker
// as the first line, declare `package main`, and expose a top-level
// `func generatedCellModules() []CellModule` function.
//
// If no modules_gen.go files exist the test passes (the rule only fires when
// the file is present; new cmd packages without codegen are not penalized).
func TestAssemblyModulesGen_HasGeneratedMarker(t *testing.T) {
	t.Parallel()
	root := findModuleRoot(t)

	matches, err := filepath.Glob(filepath.Join(root, "cmd", "*", "modules_gen.go"))
	require.NoError(t, err, "%s: glob cmd/*/modules_gen.go", ruleAssemblyModulesGen01)

	if len(matches) == 0 {
		t.Logf("%s: no cmd/*/modules_gen.go files found — nothing to enforce", ruleAssemblyModulesGen01)
		return
	}

	for _, path := range matches {
		path := path
		rel, _ := filepath.Rel(root, path)
		t.Run(rel, func(t *testing.T) {
			t.Parallel()
			checkModulesGenFile(t, path, rel)
		})
	}
}

// checkModulesGenFile verifies the three ASSEMBLY-MODULES-GEN-01 invariants
// for a single modules_gen.go file.
func checkModulesGenFile(t *testing.T, path, rel string) {
	t.Helper()

	// 1. First line must be the exact DO NOT EDIT marker.
	f, err := os.Open(filepath.Clean(path))
	require.NoError(t, err, "%s: open %s", ruleAssemblyModulesGen01, rel)
	defer func() { require.NoError(t, f.Close()) }()

	scanner := bufio.NewScanner(f)
	require.True(t, scanner.Scan(),
		"%s: %s is empty — must start with DO NOT EDIT marker", ruleAssemblyModulesGen01, rel)
	firstLine := scanner.Text()
	assert.True(t,
		strings.HasPrefix(firstLine, generatedMarkerPrefix),
		"%s: %s first line must be %q; got %q",
		ruleAssemblyModulesGen01, rel, generatedMarkerPrefix, firstLine,
	)

	// 2 & 3. Parse the AST to verify package main + generatedCellModules.
	fset := token.NewFileSet()
	af, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
	require.NoError(t, err, "%s: parse %s", ruleAssemblyModulesGen01, rel)

	assert.Equal(t, "main", af.Name.Name,
		"%s: %s must declare `package main`", ruleAssemblyModulesGen01, rel)

	assert.True(t, hasGeneratedCellModulesFunc(af),
		"%s: %s must declare top-level `func generatedCellModules() []CellModule`; "+
			"run `gocell generate assembly` to regenerate",
		ruleAssemblyModulesGen01, rel,
	)
}

// hasGeneratedCellModulesFunc returns true when the file contains a top-level
// function declaration `func generatedCellModules() []CellModule`.
func hasGeneratedCellModulesFunc(af *ast.File) bool {
	for _, decl := range af.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok || fn.Recv != nil {
			continue // skip non-functions and methods
		}
		if fn.Name.Name != "generatedCellModules" {
			continue
		}
		ft := fn.Type
		// No parameters.
		if ft.Params != nil && len(ft.Params.List) != 0 {
			continue
		}
		// Returns exactly one result: []CellModule.
		if ft.Results == nil || len(ft.Results.List) != 1 {
			continue
		}
		result := ft.Results.List[0]
		arr, ok := result.Type.(*ast.ArrayType)
		if !ok || arr.Len != nil {
			continue
		}
		id, ok := arr.Elt.(*ast.Ident)
		if !ok || id.Name != "CellModule" {
			continue
		}
		return true
	}
	return false
}

// INVARIANT: ASSEMBLY-MODULES-SWITCH-FORBIDDEN-02
//
// TestRunGoNoCellIDSwitch enforces ASSEMBLY-MODULES-SWITCH-FORBIDDEN-02:
// no Go source file under cmd/ may contain a switch statement with case labels
// that are known cell-ID string literals. The cell-ID dispatch was replaced by
// generatedCellModules(); re-introducing the switch pattern defeats the
// single-source-of-truth guarantee provided by modules_gen.go.
func TestRunGoNoCellIDSwitch(t *testing.T) {
	t.Parallel()
	root := findModuleRoot(t)
	cmdDir := filepath.Join(root, "cmd")

	knownCellIDs := loadKnownCellIDs(t)
	knownIDSet := make(map[string]struct{}, len(knownCellIDs))
	for _, id := range knownCellIDs {
		knownIDSet[id] = struct{}{}
	}

	// Collect all non-test .go files under cmd/.
	var goFiles []string
	walkErr := filepath.WalkDir(cmdDir, func(path string, d os.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			if d.Name() == "vendor" || d.Name() == "testdata" {
				return filepath.SkipDir
			}
			return nil
		}
		if strings.HasSuffix(path, ".go") && !strings.HasSuffix(path, "_test.go") {
			goFiles = append(goFiles, path)
		}
		return nil
	})
	require.NoError(t, walkErr, "%s: walk cmd/", ruleAssemblySwitchForbidden02)

	type violation struct {
		file   string
		line   int
		cellID string
	}
	var violations []violation

	fset := token.NewFileSet()
	for _, path := range goFiles {
		af, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
		if err != nil {
			// Unparseable files are a build error; surface but don't block.
			t.Logf("%s: parse %s: %v", ruleAssemblySwitchForbidden02, path, err)
			continue
		}
		ast.Inspect(af, func(n ast.Node) bool {
			sw, ok := n.(*ast.SwitchStmt)
			if !ok {
				return true
			}
			for _, stmt := range sw.Body.List {
				cc, ok := stmt.(*ast.CaseClause)
				if !ok {
					continue
				}
				for _, expr := range cc.List {
					lit, ok := expr.(*ast.BasicLit)
					if !ok || lit.Kind != token.STRING {
						continue
					}
					unquoted, err := strconv.Unquote(lit.Value)
					if err != nil {
						continue
					}
					if _, found := knownIDSet[unquoted]; found {
						pos := fset.Position(lit.Pos())
						rel, _ := filepath.Rel(root, pos.Filename)
						violations = append(violations, violation{
							file:   rel,
							line:   pos.Line,
							cellID: unquoted,
						})
					}
				}
			}
			return true
		})
	}

	for _, v := range violations {
		t.Errorf("%s: %s:%d — cell-ID literal %q found as switch case; "+
			"use generatedCellModules() from modules_gen.go instead; "+
			"run `gocell generate assembly --id=<id>`",
			ruleAssemblySwitchForbidden02, v.file, v.line, v.cellID)
	}
}

// INVARIANT: ASSEMBLY-MAXCONSISTENCY-DERIVED-03
//
// TestAssemblyMetaMaxConsistencyDerivedTag enforces
// ASSEMBLY-MAXCONSISTENCY-DERIVED-03: AssemblyMeta.MaxConsistencyLevel must
// carry the struct tag `yaml:"-"` so that yaml.v3 strict-mode decoding
// rejects any yaml file that tries to set it, preserving the "derived-only"
// semantic.
func TestAssemblyMetaMaxConsistencyDerivedTag(t *testing.T) {
	t.Parallel()
	root := findModuleRoot(t)
	srcPath := filepath.Join(root, "kernel", "metadata", "types.go")

	fset := token.NewFileSet()
	af, err := parser.ParseFile(fset, srcPath, nil, parser.SkipObjectResolution)
	require.NoError(t, err, "%s: parse %s", ruleAssemblyMaxConsistencyDerived03, srcPath)

	structType := findStructDecl(af, "AssemblyMeta")
	require.NotNil(t, structType,
		"%s: type AssemblyMeta struct not found in %s",
		ruleAssemblyMaxConsistencyDerived03, srcPath)

	for _, field := range structType.Fields.List {
		for _, name := range field.Names {
			if name.Name != "MaxConsistencyLevel" {
				continue
			}
			pos := fset.Position(field.Pos())
			rel, _ := filepath.Rel(root, pos.Filename)

			require.NotNil(t, field.Tag,
				"%s: %s:%d AssemblyMeta.MaxConsistencyLevel has no struct tag; "+
					"must be `yaml:\"-\"` to prevent yaml override of derived field",
				ruleAssemblyMaxConsistencyDerived03, rel, pos.Line)

			tag := field.Tag.Value // raw literal including backticks
			// tag looks like "`yaml:\"-\" foo:\"bar\"`"
			unquoted, err := strconv.Unquote(tag)
			if err != nil {
				// tag is a raw string literal (`...`), strip the surrounding backticks.
				unquoted = strings.Trim(tag, "`")
			}

			assert.True(t,
				containsYAMLDashTag(unquoted),
				"%s: %s:%d AssemblyMeta.MaxConsistencyLevel struct tag is %q; "+
					"must be `yaml:\"-\"` to prevent yaml override of derived field",
				ruleAssemblyMaxConsistencyDerived03, rel, pos.Line, tag,
			)
			return // field found; test done
		}
	}

	t.Errorf("%s: field MaxConsistencyLevel not found in AssemblyMeta — "+
		"ensure the field exists and carries `yaml:\"-\"`",
		ruleAssemblyMaxConsistencyDerived03)
}

// containsYAMLDashTag reports whether the raw struct tag string contains a
// yaml tag whose value is exactly "-". It handles both `yaml:"-"` alone and
// mixed tags like `yaml:"-" json:"foo"`.
func containsYAMLDashTag(rawTag string) bool {
	// Use Go's reflect.StructTag semantics via manual parsing to avoid
	// importing reflect in the test. The yaml tag value is the portion between
	// `yaml:"` and `"`, handling the first comma-separated segment.
	const prefix = `yaml:"`
	idx := strings.Index(rawTag, prefix)
	if idx < 0 {
		return false
	}
	rest := rawTag[idx+len(prefix):]
	end := strings.Index(rest, `"`)
	if end < 0 {
		return false
	}
	tagVal := rest[:end]
	// The yaml tag value for "yaml:"-"" is "-" (exactly).
	// If it contains a comma (e.g. "yaml:"name,omitempty""), split on the first comma.
	tagVal = strings.SplitN(tagVal, ",", 2)[0]
	return tagVal == "-"
}

// findStructDecl returns the *ast.StructType for `type <name> struct { … }` in
// af, or nil if not found.
func findStructDecl(af *ast.File, name string) *ast.StructType {
	for _, decl := range af.Decls {
		gen, ok := decl.(*ast.GenDecl)
		if !ok || gen.Tok != token.TYPE {
			continue
		}
		for _, spec := range gen.Specs {
			ts, ok := spec.(*ast.TypeSpec)
			if !ok || ts.Name.Name != name {
				continue
			}
			if st, ok := ts.Type.(*ast.StructType); ok {
				return st
			}
		}
	}
	return nil
}

// INVARIANT: ASSEMBLY-CELLMODULE-TYPE-04
//
// TestAssemblyCellModuleTypePresent enforces ASSEMBLY-CELLMODULE-TYPE-04:
// whenever cmd/{id}/modules_gen.go exists, the same cmd/{id}/ package must
// declare a top-level type named "CellModule" (interface or struct, both are
// valid). Without it, modules_gen.go cannot compile because it references
// CellModule in its return type, but the resulting compiler error
// ("undefined: CellModule") gives no actionable guidance. This rule provides
// a fail-fast message that points users to the correct scaffold command.
//
// rationale: K#10 introduced the cmd-package-local type contract
// (modules_gen.go references CellModule type). Guarding it here prevents
// silent breakage and follows the three-piece constraint closure rule:
// static guard + documentation contract + regression test.
//
// ref: user feedback memory feedback_constraint_self_close — implicit
// constraints must ship with three-piece closure in the same PR (static
// guard + doc contract + regression test).
func TestAssemblyCellModuleTypePresent(t *testing.T) {
	t.Parallel()
	root := findModuleRoot(t)

	matches, err := filepath.Glob(filepath.Join(root, "cmd", "*", "modules_gen.go"))
	require.NoError(t, err, "%s: glob cmd/*/modules_gen.go", ruleAssemblyCellModuleType04)

	if len(matches) == 0 {
		t.Logf("%s: no cmd/*/modules_gen.go files found — nothing to enforce", ruleAssemblyCellModuleType04)
		return
	}

	for _, modulesGen := range matches {
		modulesGen := modulesGen
		cmdDir := filepath.Dir(modulesGen)
		rel, _ := filepath.Rel(root, cmdDir)
		t.Run(rel, func(t *testing.T) {
			t.Parallel()
			checkCellModuleTypePresentInDir(t, root, cmdDir)
		})
	}
}

// checkCellModuleTypePresentInDir scans all non-test *.go files in cmdDir for
// a top-level type declaration named "CellModule". It reports an
// ASSEMBLY-CELLMODULE-TYPE-04 violation when no such declaration is found.
func checkCellModuleTypePresentInDir(t *testing.T, root, cmdDir string) {
	t.Helper()

	goFiles, err := filepath.Glob(filepath.Join(cmdDir, "*.go"))
	require.NoError(t, err, "%s: glob %s/*.go", ruleAssemblyCellModuleType04, cmdDir)

	fset := token.NewFileSet()
	for _, path := range goFiles {
		if strings.HasSuffix(path, "_test.go") {
			continue
		}
		af, parseErr := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
		if parseErr != nil {
			t.Logf("%s: parse %s: %v", ruleAssemblyCellModuleType04, path, parseErr)
			continue
		}
		if hasTopLevelTypeDecl(af, "CellModule") {
			return // found — rule satisfied
		}
	}

	rel, _ := filepath.Rel(root, cmdDir)
	t.Errorf(
		"%s: cmd/%s/modules_gen.go references CellModule but cmd/%s/ has no "+
			"top-level CellModule type declaration. "+
			"Define `type CellModule interface { ID() string; ... }` (or compatible) "+
			"in the same package.",
		ruleAssemblyCellModuleType04, filepath.Base(cmdDir), filepath.Base(rel),
	)
}

// hasTopLevelTypeDecl reports whether af contains a top-level type declaration
// with the given name, regardless of whether it is an interface, struct, or
// any other type kind.
func hasTopLevelTypeDecl(af *ast.File, name string) bool {
	for _, decl := range af.Decls {
		gen, ok := decl.(*ast.GenDecl)
		if !ok || gen.Tok != token.TYPE {
			continue
		}
		for _, spec := range gen.Specs {
			ts, ok := spec.(*ast.TypeSpec)
			if ok && ts.Name.Name == name {
				return true
			}
		}
	}
	return false
}

// ---- ASSEMBLY-SNAPSHOTS-LOCKED-01 ----
//
// INVARIANT: ASSEMBLY-SNAPSHOTS-LOCKED-01
//
// TestAssemblySnapshotsLocked enforces ASSEMBLY-SNAPSHOTS-LOCKED-01 by walking
// every production .go file under kernel/assembly/ and flagging unlocked
// writes to *.snapshots.
//
// Invariant: every write to *CoreAssembly.snapshots in kernel/assembly/
// production code must be lexically inside a Lock()/Unlock() critical section
// on the receiver's mu. Detection prevents regression of the fatal map race
// fixed in PR-V1-030-K01-ASSEMBLY-SNAPSHOTS-RACE-FIX (G1-01, review
// 20260504): Phase 1 of startInternal previously wrote a.snapshots[c.ID()]
// without holding a.mu, racing against Snapshots() readers that hold a.mu.

const ruleAssemblySnapshotsLocked01 = "ASSEMBLY-SNAPSHOTS-LOCKED-01"

func TestAssemblySnapshotsLocked(t *testing.T) {
	root := findModuleRoot(t)
	files, err := asnFindAssemblyProductionGoFiles(root)
	if err != nil {
		t.Fatalf("walking kernel/assembly/: %v", err)
	}
	if len(files) == 0 {
		t.Fatal("no production .go files found under kernel/assembly/")
	}

	var violations []string
	for _, path := range files {
		rel, _ := filepath.Rel(root, path)
		rel = filepath.ToSlash(rel)
		vs, err := asnCheckFile(path, rel)
		if err != nil {
			t.Fatalf("parsing %s: %v", rel, err)
		}
		violations = append(violations, vs...)
	}

	sort.Strings(violations)
	for _, v := range violations {
		t.Errorf("%s", v)
	}
}

// TestAssemblySnapshotsLocked_DetectsViolation is a self-test ensuring the
// detector flags an unlocked write. Without this guard a buggy detector
// could silently pass and let the original race regress.
func TestAssemblySnapshotsLocked_DetectsViolation(t *testing.T) {
	src := `package x
type A struct { snapshots map[string]int }
func (a *A) bug() {
    a.snapshots["k"] = 1
}`
	vs, err := asnCheckSource("<fixture-bug>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag unlocked a.snapshots[k] = ...")
	}
}

// TestAssemblySnapshotsLocked_DetectsWholeMapWrite verifies whole-map
// replacement (`a.snapshots = ...`) outside a lock is flagged.
func TestAssemblySnapshotsLocked_DetectsWholeMapWrite(t *testing.T) {
	src := `package x
type A struct { snapshots map[string]int }
func (a *A) bug() {
    a.snapshots = map[string]int{}
}`
	vs, err := asnCheckSource("<fixture-whole>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag unlocked whole-map write a.snapshots = ...")
	}
}

// TestAssemblySnapshotsLocked_DetectsUnlockedDelete verifies that an unlocked
// delete(a.snapshots, k) is flagged.
func TestAssemblySnapshotsLocked_DetectsUnlockedDelete(t *testing.T) {
	src := `package x
type A struct { snapshots map[string]int }
func (a *A) bug() {
    delete(a.snapshots, "k")
}`
	vs, err := asnCheckSource("<fixture-delete>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag unlocked delete(a.snapshots, ...)")
	}
}

// TestAssemblySnapshotsLocked_AllowsLockedWrite verifies the detector treats
// writes inside a Lock()/Unlock() pair as compliant.
func TestAssemblySnapshotsLocked_AllowsLockedWrite(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) ok() {
    a.mu.Lock()
    a.snapshots["k"] = 1
    a.mu.Unlock()
}`
	vs, err := asnCheckSource("<fixture-locked>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) != 0 {
		t.Errorf("expected no violations for locked write, got: %v", vs)
	}
}

func TestAssemblySnapshotsLocked_DetectsPerKeyWriteLockedByDifferentReceiver(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) bug(b *A) {
    b.mu.Lock()
    defer b.mu.Unlock()
    a.snapshots["k"] = 1
}`
	vs, err := asnCheckSource("<fixture-wrong-mutex-key>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag a.snapshots[k] write protected only by b.mu")
	}
}

func TestAssemblySnapshotsLocked_DetectsWholeMapWriteLockedByDifferentReceiver(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) bug(b *A, m map[string]int) {
    b.mu.Lock()
    defer b.mu.Unlock()
    a.snapshots = m
}`
	vs, err := asnCheckSource("<fixture-wrong-mutex-whole>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag whole-map a.snapshots write protected only by b.mu")
	}
}

func TestAssemblySnapshotsLocked_DetectsDeleteLockedByDifferentReceiver(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) bug(b *A) {
    b.mu.Lock()
    defer b.mu.Unlock()
    delete(a.snapshots, "k")
}`
	vs, err := asnCheckSource("<fixture-wrong-mutex-delete>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag delete(a.snapshots, ...) protected only by b.mu")
	}
}

func TestAssemblySnapshotsLocked_AllowsEachReceiverProtectedByOwnMutex(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) ok(b *A) {
    a.mu.Lock()
    b.mu.Lock()
    a.snapshots["a"] = 1
    b.snapshots["b"] = 2
    delete(a.snapshots, "a")
    b.mu.Unlock()
    a.mu.Unlock()
}`
	vs, err := asnCheckSource("<fixture-each-receiver>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) != 0 {
		t.Errorf("expected no violations when each snapshots receiver has its own mutex locked, got: %v", vs)
	}
}

// TestAssemblySnapshotsLocked_AllowsDeferUnlock verifies that
// `defer a.mu.Unlock()` keeps the lock held for the remainder of the body.
func TestAssemblySnapshotsLocked_AllowsDeferUnlock(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) ok() {
    a.mu.Lock()
    defer a.mu.Unlock()
    a.snapshots["k"] = 1
    delete(a.snapshots, "x")
    a.snapshots = map[string]int{}
}`
	vs, err := asnCheckSource("<fixture-defer>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) != 0 {
		t.Errorf("expected no violations for defer-unlock pattern, got: %v", vs)
	}
}

// TestAssemblySnapshotsLocked_AllowsCompositeLiteralInit verifies that struct
// literal initialization (`&A{snapshots: make(...)}`) is not flagged. This is
// how New() seeds the field without requiring a lock.
func TestAssemblySnapshotsLocked_AllowsCompositeLiteralInit(t *testing.T) {
	src := `package x
type A struct { snapshots map[string]int }
func New() *A {
    return &A{snapshots: map[string]int{}}
}`
	vs, err := asnCheckSource("<fixture-init>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) != 0 {
		t.Errorf("expected no violations for composite-literal init, got: %v", vs)
	}
}

// TestAssemblySnapshotsLocked_DetectsViolationInGoroutineFuncLit verifies
// the FuncLit walk: a goroutine whose body writes a.snapshots without
// holding the lock must be flagged, even though the surrounding outer
// function may itself hold the lock — the goroutine runs in an independent
// scheduling context where the caller's mutex is not held.
func TestAssemblySnapshotsLocked_DetectsViolationInGoroutineFuncLit(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) outer() {
    a.mu.Lock()
    defer a.mu.Unlock()
    go func() {
        a.snapshots["k"] = 1
    }()
}`
	vs, err := asnCheckSource("<fixture-funclit>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag unlocked write inside goroutine FuncLit")
	}
}

// TestAssemblySnapshotsLocked_DetectsViolationInIfInit verifies the Init
// clause of an IfStmt is scanned. `if a.snapshots = ...; cond {}` is a
// rare-but-legal pattern, and a write hidden there must not be a blind
// spot.
func TestAssemblySnapshotsLocked_DetectsViolationInIfInit(t *testing.T) {
	src := `package x
type A struct { snapshots map[string]int }
func (a *A) bug(m map[string]int) {
    if a.snapshots = m; len(a.snapshots) > 0 {
        return
    }
}`
	vs, err := asnCheckSource("<fixture-ifinit>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) == 0 {
		t.Error("detector did not flag unlocked write hidden in IfStmt.Init")
	}
}

// TestAssemblySnapshotsLocked_AllowsLockedWriteInsideIf verifies that locks
// taken inside a nested block (e.g. an if-error path) are tracked correctly.
func TestAssemblySnapshotsLocked_AllowsLockedWriteInsideIf(t *testing.T) {
	src := `package x
import "sync"
type A struct {
    mu        sync.Mutex
    snapshots map[string]int
}
func (a *A) ok(err error) {
    if err != nil {
        a.mu.Lock()
        a.snapshots = map[string]int{}
        a.mu.Unlock()
        return
    }
}`
	vs, err := asnCheckSource("<fixture-if>", src)
	if err != nil {
		t.Fatalf("asnCheckSource: %v", err)
	}
	if len(vs) != 0 {
		t.Errorf("expected no violations for if-body locked write, got: %v", vs)
	}
}

// asnCheckFile parses a single file and returns ASSEMBLY-SNAPSHOTS-LOCKED-01
// violations.
func asnCheckFile(path, rel string) ([]string, error) {
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
	if err != nil {
		return nil, err
	}
	return asnCheckAST(fset, f, rel), nil
}

// asnCheckSource parses a Go source string and returns violations. label is
// used in violation messages in place of a file path.
func asnCheckSource(label, src string) ([]string, error) {
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, label, src, parser.SkipObjectResolution)
	if err != nil {
		return nil, err
	}
	return asnCheckAST(fset, f, label), nil
}

func asnCheckAST(fset *token.FileSet, f *ast.File, label string) []string {
	var violations []string
	for _, decl := range f.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok || fn.Body == nil {
			continue
		}
		violations = append(violations, asnScanStmts(fset, fn.Body.List, asnNewLockState(), label)...)
	}
	// Independently inspect every FuncLit (closure / goroutine body / inline
	// callback). A FuncLit owns its lock scope: writes inside a closure do
	// not inherit the caller's lockDepth, so each starts fresh at 0. The
	// outer ast.Walk catches FuncLits anywhere in the file (top-level decls,
	// nested calls, struct field initializers, ...).
	ast.Inspect(f, func(n ast.Node) bool {
		fl, ok := n.(*ast.FuncLit)
		if !ok || fl.Body == nil {
			return true
		}
		violations = append(violations, asnScanStmts(fset, fl.Body.List, asnNewLockState(), label)...)
		return true
	})
	return violations
}

type asnLockState map[string]int

func asnNewLockState() asnLockState {
	return make(asnLockState)
}

func asnCloneLocks(locks asnLockState) asnLockState {
	cp := make(asnLockState, len(locks))
	for k, v := range locks {
		cp[k] = v
	}
	return cp
}

// asnScanStmts walks a flat list of statements with receiver-bound lock state,
// recursing into nested blocks while preserving the parent's lock state.
// Lock() increments depth; Unlock() decrements; defer Unlock() does not
// affect depth (the lock is held until the function returns, after every
// statement in the body has executed).
func asnScanStmts(fset *token.FileSet, stmts []ast.Stmt, locks asnLockState, label string) []string {
	var violations []string
	for _, stmt := range stmts {
		switch s := stmt.(type) {
		case *ast.ExprStmt:
			if recv, ok := asnMuMethodReceiver(s.X, "Lock"); ok {
				locks[recv]++
			} else if recv, ok := asnMuMethodReceiver(s.X, "Unlock"); ok {
				locks[recv]--
			} else {
				if line, ok := asnUnlockedDeleteSnapshots(s.X, fset, locks); ok {
					violations = append(violations, asnViolation(label, line))
				}
			}
		case *ast.DeferStmt:
			// `defer a.mu.Unlock()` keeps the lock held for the rest of the
			// body; do not change lockDepth here.
		case *ast.AssignStmt:
			if line, ok := asnUnlockedSnapshotsWrite(s, fset, locks); ok {
				violations = append(violations, asnViolation(label, line))
			}
		case *ast.IfStmt:
			// IfStmt.Init carries `if x := f(); ...` declarations or the
			// rare `if x = ...; ...` assignment. Scan it so writes hidden
			// in the init clause aren't a blind spot.
			if s.Init != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Init}, asnCloneLocks(locks), label)...)
			}
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
			if s.Else != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Else}, asnCloneLocks(locks), label)...)
			}
		case *ast.ForStmt:
			if s.Init != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Init}, asnCloneLocks(locks), label)...)
			}
			if s.Post != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Post}, asnCloneLocks(locks), label)...)
			}
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
		case *ast.RangeStmt:
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
		case *ast.BlockStmt:
			violations = append(violations, asnScanStmts(fset, s.List, asnCloneLocks(locks), label)...)
		case *ast.SwitchStmt:
			if s.Init != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Init}, asnCloneLocks(locks), label)...)
			}
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
		case *ast.TypeSwitchStmt:
			if s.Init != nil {
				violations = append(violations, asnScanStmts(fset, []ast.Stmt{s.Init}, asnCloneLocks(locks), label)...)
			}
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
		case *ast.CaseClause:
			violations = append(violations, asnScanStmts(fset, s.Body, asnCloneLocks(locks), label)...)
		case *ast.SelectStmt:
			if s.Body != nil {
				violations = append(violations, asnScanStmts(fset, s.Body.List, asnCloneLocks(locks), label)...)
			}
		case *ast.CommClause:
			violations = append(violations, asnScanStmts(fset, s.Body, asnCloneLocks(locks), label)...)
		}
	}
	return violations
}

// asnMuMethodReceiver returns the receiver key for a call of form
// `<x>.mu.<methodName>()`.
// The .mu suffix limits matches to mutex-shaped accesses; reflection-style
// false positives on identically named methods are not a concern in
// kernel/assembly/.
func asnMuMethodReceiver(expr ast.Expr, methodName string) (string, bool) {
	call, ok := expr.(*ast.CallExpr)
	if !ok {
		return "", false
	}
	sel, ok := call.Fun.(*ast.SelectorExpr)
	if !ok || sel.Sel.Name != methodName {
		return "", false
	}
	inner, ok := sel.X.(*ast.SelectorExpr)
	if !ok {
		return "", false
	}
	if inner.Sel.Name != "mu" {
		return "", false
	}
	recv := asnReceiverKey(inner.X)
	return recv, recv != ""
}

// asnUnlockedSnapshotsWrite returns (line, true) when assign's LHS targets
// `<x>.snapshots` or `<x>.snapshots[...]` and `<x>.mu` is not locked.
func asnUnlockedSnapshotsWrite(assign *ast.AssignStmt, fset *token.FileSet, locks asnLockState) (int, bool) {
	for _, lhs := range assign.Lhs {
		if recv, ok := asnSnapshotsReceiver(lhs); ok && locks[recv] <= 0 {
			return fset.Position(assign.Pos()).Line, true
		}
	}
	return 0, false
}

// asnUnlockedDeleteSnapshots returns (line, true) when expr is
// `delete(<x>.snapshots, ...)` and `<x>.mu` is not locked.
func asnUnlockedDeleteSnapshots(expr ast.Expr, fset *token.FileSet, locks asnLockState) (int, bool) {
	call, ok := expr.(*ast.CallExpr)
	if !ok {
		return 0, false
	}
	id, ok := call.Fun.(*ast.Ident)
	if !ok || id.Name != "delete" || len(call.Args) == 0 {
		return 0, false
	}
	if recv, ok := asnSnapshotsReceiver(call.Args[0]); ok && locks[recv] <= 0 {
		return fset.Position(call.Pos()).Line, true
	}
	return 0, false
}

// asnSnapshotsReceiver reports the receiver key for a SelectorExpr
// `<x>.snapshots` (whole-map) or an IndexExpr whose collection is
// `<x>.snapshots` (per-key).
func asnSnapshotsReceiver(expr ast.Expr) (string, bool) {
	switch e := expr.(type) {
	case *ast.SelectorExpr:
		if e.Sel.Name != "snapshots" {
			return "", false
		}
		recv := asnReceiverKey(e.X)
		return recv, recv != ""
	case *ast.IndexExpr:
		if sel, ok := e.X.(*ast.SelectorExpr); ok {
			if sel.Sel.Name != "snapshots" {
				return "", false
			}
			recv := asnReceiverKey(sel.X)
			return recv, recv != ""
		}
	}
	return "", false
}

func asnReceiverKey(expr ast.Expr) string {
	switch e := expr.(type) {
	case *ast.Ident:
		return e.Name
	case *ast.SelectorExpr:
		prefix := asnReceiverKey(e.X)
		if prefix == "" {
			return ""
		}
		return prefix + "." + e.Sel.Name
	case *ast.StarExpr:
		return "*" + asnReceiverKey(e.X)
	case *ast.ParenExpr:
		return asnReceiverKey(e.X)
	}
	return ""
}

// asnViolation formats an ASSEMBLY-SNAPSHOTS-LOCKED-01 violation message.
func asnViolation(file string, line int) string {
	return ruleAssemblySnapshotsLocked01 + ": " + file + ":" + strconv.Itoa(line) +
		": write to *.snapshots without holding the matching receiver mu.Lock(); wrap with " +
		"<receiver>.mu.Lock()/<receiver>.mu.Unlock() (or rely on defer Unlock). " +
		"ref: PR-V1-030-K01-ASSEMBLY-SNAPSHOTS-RACE-FIX, G1-01"
}

// asnFindAssemblyProductionGoFiles returns all non-test .go files under
// kernel/assembly/.
func asnFindAssemblyProductionGoFiles(root string) ([]string, error) {
	var files []string
	err := filepath.WalkDir(filepath.Join(root, "kernel", "assembly"), func(path string, d os.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			switch d.Name() {
			case "vendor", "worktrees", "testdata", ".git":
				return filepath.SkipDir
			}
			return nil
		}
		if !strings.HasSuffix(path, ".go") || strings.HasSuffix(path, "_test.go") {
			return nil
		}
		files = append(files, path)
		return nil
	})
	sort.Strings(files)
	return files, err
}

// ---- ASSEMBLYREF-METHOD-SET-01 ----
//
// INVARIANT: ASSEMBLYREF-METHOD-SET-01
//
// TestAssemblyRefMethodSet enforces ASSEMBLYREF-METHOD-SET-01: the
// cell.AssemblyRef interface (kernel/cell/auth_plan.go) must declare exactly
// three methods:
//   ID() string
//   CellIDs() []string
//   Cell(id string) Cell
//
// Background: prior to refactor/529 the bootstrap layer carried a private
// assemblyWithCell sub-interface and an asmCellLookup helper that did
// asm.(assemblyWithCell) — a silent-skip type assertion when the assembly
// implementation lacked Cell(id). Promoting Cell(id) onto AssemblyRef makes
// the contract complete and lets the compiler enforce it; this test prevents
// a future refactor from re-narrowing the interface back to the two-method
// form.
//
// ref: kubernetes-sigs/controller-runtime pkg/cluster/cluster.go@main
//      — explicit interface seam, no implicit type narrowing in callers.

const assemblyRefRule01 = "ASSEMBLYREF-METHOD-SET-01"

// expectedAssemblyRefMethods is the canonical method set for cell.AssemblyRef.
// Each entry is "(<param-types>) <result-types>" — parameter and result
// names are intentionally elided so that this guard locks the capability
// (which methods exist with which types) rather than the source-level
// spelling (which is documentation). A pure parameter rename like
// `Cell(id string) Cell` → `Cell(cellID string) Cell` is intentionally
// allowed; adding/removing/retyping a method must update this map.
var expectedAssemblyRefMethods = map[string]string{
	"ID":      "() string",
	"CellIDs": "() []string",
	"Cell":    "(string) Cell",
}

func TestAssemblyRefMethodSet(t *testing.T) {
	root := findModuleRoot(t)
	srcPath := filepath.Join(root, "kernel", "cell", "auth_plan.go")

	fset := token.NewFileSet()
	af, err := parser.ParseFile(fset, srcPath, nil, parser.SkipObjectResolution)
	require.NoError(t, err, "parse %s", srcPath)

	iface := findInterfaceDecl(af, "AssemblyRef")
	require.NotNil(t, iface, "%s: type AssemblyRef interface not found in %s", assemblyRefRule01, srcPath)

	got := make(map[string]string, len(iface.Methods.List))
	for _, m := range iface.Methods.List {
		require.Len(t, m.Names, 1,
			"%s: AssemblyRef methods must be named (no embedded interfaces)", assemblyRefRule01)
		name := m.Names[0].Name
		ft, ok := m.Type.(*ast.FuncType)
		require.True(t, ok, "%s: method %s must be a FuncType", assemblyRefRule01, name)
		got[name] = formatFuncSignature(ft)
	}

	assert.Equal(t, expectedAssemblyRefMethods, got,
		"%s: cell.AssemblyRef method set drift detected. "+
			"If this is a deliberate contract change, update expectedAssemblyRefMethods "+
			"in the same PR; otherwise revert the interface narrowing/widening.",
		assemblyRefRule01)
}

// findInterfaceDecl returns the *ast.InterfaceType declared as `type <name>
// interface { … }` in af, or nil if not found.
func findInterfaceDecl(af *ast.File, name string) *ast.InterfaceType {
	for _, decl := range af.Decls {
		gen, ok := decl.(*ast.GenDecl)
		if !ok || gen.Tok != token.TYPE {
			continue
		}
		for _, spec := range gen.Specs {
			ts, ok := spec.(*ast.TypeSpec)
			if !ok || ts.Name.Name != name {
				continue
			}
			if iface, ok := ts.Type.(*ast.InterfaceType); ok {
				return iface
			}
		}
	}
	return nil
}

// formatFuncSignature renders an *ast.FuncType as "(<param-types>) <results>"
// matching the canonical types-only form used in expectedAssemblyRefMethods.
// A single result is rendered without parentheses regardless of whether the
// AST carries a name; two or more results are parenthesized. Names of both
// parameters and results are deliberately discarded — see
// expectedAssemblyRefMethods doc.
func formatFuncSignature(ft *ast.FuncType) string {
	out := "(" + formatFieldTypes(ft.Params) + ")"
	if ft.Results == nil || len(ft.Results.List) == 0 {
		return out
	}
	results := formatFieldTypes(ft.Results)
	if len(ft.Results.List) > 1 {
		results = "(" + results + ")"
	}
	return out + " " + results
}

// formatFieldTypes renders an *ast.FieldList as a comma-joined sequence of
// type expressions, ignoring all parameter / result names. A field that
// declares N names with a single type expression contributes N type
// segments (so `func(a, b string)` and `func(string, string)` both render
// as "string, string").
func formatFieldTypes(fl *ast.FieldList) string {
	if fl == nil {
		return ""
	}
	var parts []string
	for _, f := range fl.List {
		typeStr := formatExpr(f.Type)
		// One field may declare multiple names sharing the same type; one
		// type segment per name keeps the rendering equivalent to the
		// fully-spelled form `func(a string, b string)`.
		count := len(f.Names)
		if count == 0 {
			count = 1
		}
		for i := 0; i < count; i++ {
			parts = append(parts, typeStr)
		}
	}
	return joinComma(parts)
}

func joinComma(parts []string) string {
	out := ""
	for i, p := range parts {
		if i > 0 {
			out += ", "
		}
		out += p
	}
	return out
}

// formatExpr renders the small subset of ast.Expr shapes that appear in the
// AssemblyRef method set: identifiers, qualified identifiers, slice and
// fixed-size array types, and pointer types. Anything outside this set
// trips a panic — extending the interface should prompt extending this
// helper in the same change so that the archtest stays expressive instead
// of silently accepting an unfamiliar shape.
func formatExpr(e ast.Expr) string {
	switch v := e.(type) {
	case *ast.Ident:
		return v.Name
	case *ast.SelectorExpr:
		return formatExpr(v.X) + "." + v.Sel.Name
	case *ast.ArrayType:
		if v.Len == nil {
			return "[]" + formatExpr(v.Elt)
		}
		return "[" + formatExpr(v.Len) + "]" + formatExpr(v.Elt)
	case *ast.StarExpr:
		return "*" + formatExpr(v.X)
	case *ast.BasicLit:
		return v.Value
	}
	// Defensive: ASSEMBLYREF-METHOD-SET-01 should fail loudly on a method
	// signature that uses an expression shape this helper does not yet
	// handle, prompting a same-PR extension rather than silent acceptance.
	panic("assemblyref_method_set_test: unsupported ast.Expr shape; extend formatExpr when AssemblyRef gains a new signature kind")
}
